    if ($p) { [PSCustomObject]@{ PID=$_; PPID=$p.ParentProcessId; Cmd=$p.CommandLine } }
}
$procs

# Also find by port more aggressively
Write-Host "`nAll processes with :8001 context:"
Get-CimInstance Win32_Process | Where-Object { $_.CommandLine -match "8001|uvicorn" } | Select-Object ProcessId, ParentProcessId, @{N='Cmd';E={$_.CommandLine}}

# Check OpenAPI schema to see what fields ProductResponse has in the running server
