$content = Get-Content "D:\NAM_PHUONG_SOFTWARE\DU LIEU MPS\erp-nam-phuong\backend\app\schemas\master.py" -Raw
# Find ProductBase class and count its fields
$match = [regex]::Match($content, 'class ProductBase\(BaseModel\):([\s\S]*?)(?=\nclass )')
