Add-Type -TypeDefinition @'
using System;
using System.Runtime.InteropServices;
public class ProcessHelper {
    [DllImport("kernel32.dll")]
    public static extern IntPtr OpenProcess(int access, bool inherit, int pid);
    [DllImport("kernel32.dll")]
    public static extern bool TerminateProcess(IntPtr handle, int exitCode);
    [DllImport("kernel32.dll")]
    public static extern bool CloseHandle(IntPtr handle);
}
'@ -ErrorAction SilentlyContinue

foreach ($pid in @(27624, 28424, 10976)) {
    $handle = [ProcessHelper]::OpenProcess(0x0001, $false, $pid)
    if ($handle -ne [IntPtr]::Zero) {
        $result = [ProcessHelper]::TerminateProcess($handle, 1)
        [ProcessHelper]::CloseHandle($handle) | Out-Null
        Write-Host "Terminated PID $pid via kernel: $result"
    } else {
        Write-Host "Could not open PID $pid"
    }
}

Add-Type -TypeDefinition @'
using System;
using System.Runtime.InteropServices;
public class KillHelper {
    [DllImport("kernel32.dll")]
    public static extern IntPtr OpenProcess(int access, bool inherit, int pid);
    [DllImport("kernel32.dll")]
    public static extern bool TerminateProcess(IntPtr handle, int exitCode);
    [DllImport("kernel32.dll")]
    public static extern bool CloseHandle(IntPtr handle);
    public static bool Kill(int pid) {
        var h = OpenProcess(0x0001, false, pid);
        if (h == IntPtr.Zero) return false;
        var r = TerminateProcess(h, 1);
        CloseHandle(h);
        return r;
    }
}
'@
foreach ($p in @(27624, 28424, 10976)) {
    $r = [KillHelper]::Kill($p)
    Write-Host "Kill $p -> $r"
}
