// ─── Auto-tính don_gia_m2 từ gia_ban từng lớp giấy
// don_gia_m2 = sum(gia_ban_kg × dl / 1000) cho tất cả lớp có đủ dữ liệu
export function calcDonGiaM2(
  item: Pick<QuoteItem,
    'mat' | 'mat_dl' | 'song_1' | 'song_1_dl' | 'mat_1' | 'mat_1_dl' |
    'song_2' | 'song_2_dl' | 'mat_2' | 'mat_2_dl' | 'song_3' | 'song_3_dl' | 'mat_3' | 'mat_3_dl'
  >,
  giaBanMap: Record<string, number>,
): number | null {
  const layers = [
    { mk: item.mat,    dl: item.mat_dl    },
    { mk: item.song_1, dl: item.song_1_dl },
    { mk: item.mat_1,  dl: item.mat_1_dl  },
    { mk: item.song_2, dl: item.song_2_dl },
    { mk: item.mat_2,  dl: item.mat_2_dl  },
    { mk: item.song_3, dl: item.song_3_dl },
    { mk: item.mat_3,  dl: item.mat_3_dl  },
  ].filter((l): l is { mk: string; dl: number } => !!l.mk && l.dl != null && l.dl > 0)

  if (layers.length === 0) return null

  let total = 0
  for (const { mk, dl } of layers) {
    const key = paperCodeKey(mk, dl)
    const giaBan = giaBanMap[key]
    if (giaBan == null) return null  // thiếu giá 1 lớp → không auto-fill
    total += giaBan * dl / 1000
  }
  return Math.round(total)
}

